#!/usr/bin/env node
// Contrato do merge não-destrutivo usado pelo modo "patch incremental" do
// devflow:config (Step 5). Garante que aplicar uma seção NÃO toca nas demais
// seções nem no cabeçalho-comentário do .context/.devflow.yaml.
// Run: node --test tests/validation/test-config-incremental-merge.mjs

import { test } from "node:test";
import assert from "node:assert/strict";
import { mergeSection, topLevelKeys } from "../../scripts/lib/devflow-yaml-merge.mjs";

const HEADER = `# .context/.devflow.yaml — DevFlow project configuration
# Generated by: /devflow config
# Run /devflow config to reconfigure`;

// ── topLevelKeys ────────────────────────────────────────────────────

test("topLevelKeys: lista as seções de topo, ignora comentários e indentação", () => {
  const yaml = `${HEADER}

git:
  strategy: branch-flow
  protectedBranches: [main, develop]

mempalace:
  enabled: true
`;
  assert.deepEqual(topLevelKeys(yaml), ["git", "mempalace"]);
});

test("topLevelKeys: YAML vazio ou só comentários → []", () => {
  assert.deepEqual(topLevelKeys(""), []);
  assert.deepEqual(topLevelKeys("# só comentário\n"), []);
});

// ── mergeSection: anexar seção ausente ──────────────────────────────

test("mergeSection: seção ausente é anexada preservando as existentes", () => {
  const yaml = `${HEADER}

git:
  strategy: branch-flow
  prCli: gh

mempalace:
  enabled: true
  budget: 1000
`;
  const body = `grounding:
  mode: docs-only
  blockWeb: true`;
  const out = mergeSection(yaml, "grounding", body);

  // as três seções coexistem
  assert.deepEqual(topLevelKeys(out), ["git", "mempalace", "grounding"]);
  // cabeçalho preservado verbatim no topo
  assert.ok(out.startsWith(HEADER), "cabeçalho deve ser preservado");
  // git e mempalace intactos
  assert.match(out, /strategy: branch-flow/);
  assert.match(out, /prCli: gh/);
  assert.match(out, /budget: 1000/);
  // grounding adicionado
  assert.match(out, /mode: docs-only/);
  // termina com newline único
  assert.ok(out.endsWith("\n") && !out.endsWith("\n\n\n"));
});

test("mergeSection: ao anexar, separa da seção anterior por uma linha em branco", () => {
  const yaml = `${HEADER}

git:
  strategy: trunk-based
`;
  const out = mergeSection(yaml, "grounding", `grounding:\n  mode: docs-first`);
  assert.match(out, /strategy: trunk-based\n\ngrounding:/);
});

// ── mergeSection: substituir seção existente ────────────────────────

test("mergeSection: substitui seção existente sem tocar nas outras nem no cabeçalho", () => {
  const yaml = `${HEADER}

git:
  strategy: branch-flow
  prCli: gh

mempalace:
  enabled: true
  budget: 1000

grounding:
  mode: docs-first
`;
  const body = `mempalace:
  enabled: true
  budget: 500
  autoMine: post-merge`;
  const out = mergeSection(yaml, "mempalace", body);

  // ordem das seções preservada
  assert.deepEqual(topLevelKeys(out), ["git", "mempalace", "grounding"]);
  // cabeçalho preservado
  assert.ok(out.startsWith(HEADER));
  // git e grounding intactos
  assert.match(out, /strategy: branch-flow/);
  assert.match(out, /prCli: gh/);
  assert.match(out, /mode: docs-first/);
  // mempalace atualizado: novo valor entra, antigo sai
  assert.match(out, /budget: 500/);
  assert.match(out, /autoMine: post-merge/);
  assert.doesNotMatch(out, /budget: 1000/);
});

test("mergeSection: substituir a primeira seção mantém ela na primeira posição", () => {
  const yaml = `${HEADER}

git:
  strategy: branch-flow

mempalace:
  enabled: true
`;
  const out = mergeSection(yaml, "git", `git:\n  strategy: worktree\n  branchProtection: true`);
  assert.deepEqual(topLevelKeys(out), ["git", "mempalace"]);
  assert.match(out, /strategy: worktree/);
  assert.doesNotMatch(out, /strategy: branch-flow/);
  assert.match(out, /enabled: true/); // mempalace intacto
});

// ── robustez ────────────────────────────────────────────────────────

test("mergeSection: corpo com newlines/whitespace nas pontas é normalizado", () => {
  const yaml = `${HEADER}\n\ngit:\n  strategy: branch-flow\n`;
  const out = mergeSection(yaml, "grounding", `\n\ngrounding:\n  mode: docs-only\n\n\n`);
  assert.ok(!out.includes("\n\n\n"), "sem linhas em branco triplas");
  assert.ok(out.endsWith("\n"));
  assert.match(out, /mode: docs-only/);
});

test("mergeSection: nome divergente do cabeçalho do corpo lança erro", () => {
  assert.throws(
    () => mergeSection("git:\n  strategy: x\n", "mempalace", "grounding:\n  mode: docs-only"),
    /corpo da seção 'mempalace'/,
  );
});
